/* EXPORTURI CORECTE PENTRU app.js */
export const recipes = BUDGET_RECIPES;
export default BUDGET_RECIPES;
export { BUDGET_RECIPES };


// =============================
// Adapter -> schema compatibilă cu app.js (recipes.js)
// =============================
const BUDGET_RECIPES_COMPAT = BUDGET_RECIPES.map((r, idx) => {
  // dacă rețeta e simplă (title + country + ingredients[]), o convertim
  const title = r.title || r.name || `Budget recipe ${idx + 1}`;
  const country = r.country || r.origin || "World";

  // ingredients poate fi array de stringuri OR array de obiecte
  // transformăm în array de stringuri
  const ingList = Array.isArray(r.ingredients)
    ? r.ingredients.map((x) => (typeof x === "string" ? x : (x.item || x.name || ""))).filter(Boolean)
    : [];

  // construim exact forma folosită de app.js:
  // name[lang], origin[lang], ingredients[lang]
  const langs = ["ro","en","es","fr","de","pt","ru","ar","zh","ja","hi","tr","it","ko"];

  const nameByLang = {};
  const originByLang = {};
  const ingredientsByLang = {};

  langs.forEach((lg) => {
    nameByLang[lg] = title;          // (pentru buget: același titlu peste tot dacă nu ai traduceri)
    originByLang[lg] = country;      // (idem)
    ingredientsByLang[lg] = ingList; // listă de stringuri, compatibilă
  });

  return {
    id: r.id || `budget_${idx + 1}`,
    name: nameByLang,
    origin: originByLang,
    category: { ro: "Buget", en: "Budget" }, // nu e critic, dar e util
    ingredients: ingredientsByLang
  };
});


